(function(){
/* ── Galería de imágenes ─────────────────────────────────────────── */
var initGallery=function(){
  var mainImg=document.getElementById("fq-sp-main-img");
  if(!mainImg){return}
  var thumbs=document.querySelectorAll(".fq-sp-gallery__thumb");
  thumbs.forEach(function(btn){
    btn.addEventListener("click",function(){
      var full=btn.getAttribute("data-full");
      if(full&&mainImg){mainImg.src=full}
      thumbs.forEach(function(t){t.classList.remove("is-active")});
      btn.classList.add("is-active")
    })
  })
};

/* ── Tabs de producto ────────────────────────────────────────────── */
var initTabs=function(){
  var wrap=document.querySelector("[data-fq-tabs]");
  if(!wrap){return}
  var btns=wrap.querySelectorAll(".fq-sp-tabs__btn");
  var panels=wrap.querySelectorAll(".fq-sp-tabs__panel");
  btns.forEach(function(btn){
    btn.addEventListener("click",function(){
      var target=btn.getAttribute("data-tab");
      btns.forEach(function(b){
        var active=b.getAttribute("data-tab")===target;
        b.classList.toggle("is-active",active);
        b.setAttribute("aria-selected",active?"true":"false")
      });
      panels.forEach(function(panel){
        var active=panel.id==="fq-tab-panel-"+target;
        panel.classList.toggle("is-active",active);
        if(active){panel.removeAttribute("hidden")}else{panel.setAttribute("hidden","")}
      })
    })
  })
};

/* ── Scroll horizontal productos relacionados ────────────────────── */
var initRelated=function(){
  var track=document.querySelector("[data-fq-related-track]");
  if(!track){return}
  var prev=document.querySelector(".fq-sp-related__arrow--prev");
  var next=document.querySelector(".fq-sp-related__arrow--next");
  var scrollAmount=function(){
    var card=track.querySelector(".fp-card");
    if(!card){return 280}
    return card.offsetWidth+parseInt(getComputedStyle(track).gap||"0",10)
  };
  if(prev){prev.addEventListener("click",function(){track.scrollBy({left:-scrollAmount(),behavior:"smooth"})})}
  if(next){next.addEventListener("click",function(){track.scrollBy({left:scrollAmount(),behavior:"smooth"})})}
};

/* ── Ocultar "Ver carrito" tras añadir al carrito ────────────────── */
var initHideViewCart=function(){
  /* WooCommerce dispara este evento jQuery al completar el AJAX add-to-cart */
  if(typeof jQuery==="undefined"){return}
  jQuery(document.body).on("added_to_cart",function(){
    /* Enlace "Ver carrito" que WooCommerce inyecta junto al botón */
    document.querySelectorAll(".wc-forward,.added_to_cart").forEach(function(el){
      el.style.display="none"
    })
  })
  /* También ocultamos si ya existe al cargar (ej. tras recarga de página) */
  document.querySelectorAll(".wc-forward,.added_to_cart").forEach(function(el){
    el.style.display="none"
  })
};

/* ── Init ────────────────────────────────────────────────────────── */
var init=function(){initGallery();initTabs();initRelated();initHideViewCart()};
if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",init)}else{init()}
})();
